  1→/**
  2→ * DealRepository - CRUD operations for Deal model
  3→ *
  4→ * Provides typed methods for Deal queries with soft-delete support.
  5→ * Handles Deal stage transitions with history tracking.
  6→ */
  7→
  8→import { prisma } from './prisma';
  9→import type {
 10→  Deal,
 11→  DealHistory,
 12→  Prisma,
 13→} from '@prisma/client';
 14→import { randomUUID } from 'node:crypto';
 15→
 16→/**
 17→ * Deal creation input type
 18→ */
 19→export type DealCreateInput = Omit<Prisma.DealUncheckedCreateInput, 'id' | 'number' | 'createdAt' | 'updatedAt'>;
 20→
 21→/**
 22→ * Deal update input type
 23→ */
 24→export type DealUpdateInput = Prisma.DealUncheckedUpdateInput;
 25→
 26→/**
 27→ * Deal findMany params type
 28→ */
 29→export type DealFindManyParams = {
 30→  where?: Prisma.DealWhereInput;
 31→  orderBy?: Prisma.DealOrderByWithRelationInput;
 32→  skip?: number;
 33→  take?: number;
 34→  include?: Prisma.DealInclude;
 35→};
 36→
 37→/**
 38→ * Repository for Deal CRUD operations
 39→ */
 40→export class DealRepository {
 41→  /**
 42→   * Generate deal number in format С-YYYY-NNNNN
 43→   */
 44→  private generateNumber(): string {
 45→    const year = new Date().getFullYear();
 46→    const random = Math.floor(Math.random() * 99999).toString().padStart(5, '0');
 47→    return `С-${year}-${random}`;
 48→  }
 49→
 50→  /**
 51→   * Find many deals with optional filtering
 52→   * Automatically filters out soft-deleted records
 53→   */
 54→  async findMany(params?: DealFindManyParams): Promise<Deal[]> {
 55→    const { where, ...rest } = params ?? {};
 56→
 57→    return prisma.deal.findMany({
 58→      ...rest,
 59→      where: {
 60→        ...where,
 61→        deletedAt: null, // Always exclude soft-deleted
 62→      },
 63→    });
 64→  }
 65→
 66→  /**
 67→   * Find a single deal by ID
 68→   * Returns null if not found or soft-deleted
 69→   */
 70→  async findUnique(
 71→    id: string,
 72→    include?: Prisma.DealInclude
 73→  ): Promise<Deal | null> {
 74→    return prisma.deal.findFirst({
 75→      where: { id, deletedAt: null },
 76→      include,
 77→    });
 78→  }
 79→
 80→  /**
 81→   * Find deals by pipeline ID
 82→   */
 83→  async findByPipeline(pipelineId: string): Promise<Deal[]> {
 84→    return this.findMany({
 85→      where: { pipelineId },
 86→      orderBy: { createdAt: 'desc' },
 87→    });
 88→  }
 89→
 90→  /**
 91→   * Find deals by stage ID
 92→   */
 93→  async findByStage(stageId: string): Promise<Deal[]> {
 94→    return this.findMany({
 95→      where: { stageId },
 96→      orderBy: { createdAt: 'desc' },
 97→    });
 98→  }
 99→
100→  /**
101→   * Find deals by manager (owner)
102→   */
103→  async findByManager(managerId: string): Promise<Deal[]> {
104→    return this.findMany({
105→      where: { managerId },
106→      orderBy: { createdAt: 'desc' },
107→    });
108→  }
109→
110→  /**
111→   * Find deals by contact
112→   */
113→  async findByContact(contactId: string): Promise<Deal[]> {
114→    return this.findMany({
115→      where: { contactId },
116→      orderBy: { createdAt: 'desc' },
117→    });
118→  }
119→
120→  /**
121→   * Create a new deal
122→   * Generates UUID, number, and timestamps if not provided
123→   */
124→  async create(data: DealCreateInput): Promise<Deal> {
125→    const now = new Date();
126→
127→    return prisma.deal.create({
128→      data: {
129→        ...data,
130→        id: data.id ?? randomUUID(),
131→        number: data.number ?? this.generateNumber(),
132→        createdAt: data.createdAt ?? now,
133→        updatedAt: data.updatedAt ?? now,
134→      },
135→    });
136→  }
137→
138→  /**
139→   * Update an existing deal
140→   * Throws RecordNotFound if deal doesn't exist or is soft-deleted
141→   */
142→  async update(
143→    id: string,
144→    data: DealUpdateInput
145→  ): Promise<Deal> {
146→    // Verify deal exists and not deleted
147→    const existing = await this.findUnique(id);
148→    if (!existing) {
149→      throw new Error(`Deal with id ${id} not found`);
150→    }
151→
152→    return prisma.deal.update({
153→      where: { id },
154→      data: {
155→        ...data,
156→        updatedAt: new Date(),
157→      },
158→    });
159→  }
160→
161→  /**
162→   * Move deal to a different stage
163→   * Records the transition in DealHistory
164→   */
165→  async moveStage(
166→    dealId: string,
167→    toStageId: string,
168→    changedBy: string,
169→    comment?: string
170→  ): Promise<Deal> {
171→    const deal = await this.findUnique(dealId);
172→    if (!deal) {
173→      throw new Error(`Deal with id ${dealId} not found`);
174→    }
175→
176→    const fromStageId = deal.stageId;
177→
178→    // Record history
179→    await prisma.dealHistory.create({
180→      data: {
181→        id: randomUUID(),
182→        dealId,
183→        fromStageId,
184→        toStageId,
185→        comment: comment ?? null,
186→        changedBy,
187→        changedAt: new Date(),
188→      },
189→    });
190→
191→    // Update deal stage
192→    const updated = await prisma.deal.update({
193→      where: { id: dealId },
194→      data: {
195→        stageId: toStageId,
196→        updatedAt: new Date(),
197→      },
198→    });
199→
200→    // Set closedAt if moved to won/lost stage
201→    const stage = await prisma.dealStage.findUnique({
202→      where: { id: toStageId },
203→    });
204→    if (stage && (stage.isWonStage || stage.isLostStage)) {
205→      await prisma.deal.update({
206→        where: { id: dealId },
207→        data: {
208→          actualCloseDate: new Date(),
209→          closedAt: new Date(),
210→        },
211→      });
212→    }
213→
214→    return updated;
215→  }
216→
217→  /**
218→   * Soft delete a deal by setting deletedAt timestamp
219→   * Does NOT actually delete the record from database
220→   */
221→  async softDelete(id: string): Promise<Deal> {
222→    // Verify deal exists and not already deleted
223→    const existing = await this.findUnique(id);
224→    if (!existing) {
225→      throw new Error(`Deal with id ${id} not found`);
226→    }
227→
228→    return prisma.deal.update({
229→      where: { id },
230→      data: { deletedAt: new Date() },
231→    });
232→  }
233→
234→  /**
235→   * Count deals matching criteria (excluding soft-deleted)
236→   */
237→  async count(where?: Prisma.DealWhereInput): Promise<number> {
238→    return prisma.deal.count({
239→      where: {
240→        ...where,
241→        deletedAt: null,
242→      },
243→    });
244→  }
245→
246→  /**
247→   * Get deal history entries
248→   */
249→  async getHistory(dealId: string): Promise<DealHistory[]> {
250→    return prisma.dealHistory.findMany({
251→      where: { dealId },
252→      orderBy: { changedAt: 'desc' },
253→    });
254→  }
255→}
256→
257→/**
258→ * Singleton instance for use across the application
259→ */
260→export const deals = new DealRepository();
261→
262→export default deals;
263→

